#[cfg(feature = "netcdf4")]
#[test]
fn test_nc4_basic() {
    let path = skip_if_missing!("netcdf4", "nc4_basic.nc");
    let file = netcdf_reader::NcFile::open_with_options(
        &path,
        netcdf_reader::NcOpenOptions {
            metadata_mode: netcdf_reader::NcMetadataMode::Lossy,
            ..Default::default()
        },
    )
    .unwrap();

    assert!(matches!(
        file.format(),
        netcdf_reader::NcFormat::Nc4 | netcdf_reader::NcFormat::Nc4Classic
    ));

    let dims = file.dimensions().unwrap();
    assert!(dims.len() >= 2);

    let vars = file.variables().unwrap();
    assert!(!vars.is_empty());
}

